opencat.script:
// ===== Scene 1 入场（0s）— slam + 贴纸 stagger =====
ctx.fromTo('s1-kicker', { opacity: 0, x: -24 }, { opacity: 1, x: 0, duration: 0.4, delay: 0.05, ease: 'power3.out' });
ctx.fromTo('s1-hero', { opacity: 0, scale: 1.25, rotation: -14, y: -30 }, { opacity: 1, scale: 1, rotation: -2, y: 0, duration: 0.6, delay: 0.1, ease: 'back.out' });
ctx.fromTo('s1-hero-t', { opacity: 0, y: 24 }, { opacity: 1, y: 0, duration: 0.4, delay: 0.25, ease: 'power2.out' });
ctx.fromTo('s1-my', { opacity: 0, scale: 0.3, rotation: 40 }, { opacity: 1, scale: 1, rotation: 6, duration: 0.5, delay: 0.55, ease: 'back.out' });
ctx.fromTo('s1-stk1', { opacity: 0, scale: 0.5, rotation: -20 }, { opacity: 1, scale: 1, rotation: 3, duration: 0.45, delay: 0.45, ease: 'back.out' });
ctx.fromTo('s1-stk2', { opacity: 0, scale: 0.5, rotation: 20 }, { opacity: 1, scale: 1, rotation: -2, duration: 0.45, delay: 0.55, ease: 'back.out' });
ctx.fromTo('s1-stk3', { opacity: 0, scale: 0.5, rotation: -18 }, { opacity: 1, scale: 1, rotation: 2, duration: 0.45, delay: 0.65, ease: 'back.out' });
ctx.fromTo('s1-star', { opacity: 0, scale: 0, rotation: -90 }, { opacity: 1, scale: 1, rotation: 0, duration: 0.5, delay: 0.75, ease: 'back.out' });
ctx.fromTo('s1-meta', { opacity: 0 }, { opacity: 1, duration: 0.4, delay: 0.8, ease: 'power2.out' });

// ===== Scene 2 入场（3.4s）— 贴纸对 snap =====
ctx.fromTo('s2-kicker', { opacity: 0, y: -16 }, { opacity: 1, y: 0, duration: 0.4, delay: 3.4, ease: 'power3.out' });
ctx.fromTo('s2-blockA', { opacity: 0, x: -50, rotation: -18 }, { opacity: 1, x: 0, rotation: -3, duration: 0.5, delay: 3.45, ease: 'back.out' });
ctx.fromTo('s2-blockB', { opacity: 0, x: 50, rotation: 18 }, { opacity: 1, x: 0, rotation: 2, duration: 0.5, delay: 3.6, ease: 'back.out' });
ctx.fromTo('s2-arrow', { opacity: 0, scale: 0.2, rotation: -30 }, { opacity: 1, scale: 1, rotation: 0, duration: 0.45, delay: 3.85, ease: 'back.out' });
ctx.fromTo('s2-star', { opacity: 0, scale: 0, rotation: -120 }, { opacity: 1, scale: 1, rotation: 0, duration: 0.5, delay: 3.7, ease: 'back.out' });
ctx.fromTo('s2-tagline', { opacity: 0, y: 18 }, { opacity: 1, y: 0, duration: 0.4, delay: 3.95, ease: 'power2.out' });

// ===== Scene 3 入场（6.8s）— 三卡 assemble =====
ctx.fromTo('s3-kicker', { opacity: 0, x: -20 }, { opacity: 1, x: 0, duration: 0.4, delay: 6.8, ease: 'power3.out' });
ctx.fromTo('s3-title', { opacity: 0, y: 28 }, { opacity: 1, y: 0, duration: 0.5, delay: 6.82, ease: 'power3.out' });
ctx.fromTo('s3-underline', { opacity: 0, scaleX: 0 }, { opacity: 1, scaleX: 1, duration: 0.45, delay: 6.95, ease: 'power2.out' });
ctx.fromTo('s3-c1', { opacity: 0, y: 70, rotation: -10 }, { opacity: 1, y: 0, rotation: -2, duration: 0.5, delay: 6.9, ease: 'back.out' });
ctx.fromTo('s3-c2', { opacity: 0, y: 70, rotation: 8 }, { opacity: 1, y: 0, rotation: 1, duration: 0.5, delay: 7.02, ease: 'back.out' });
ctx.fromTo('s3-c3', { opacity: 0, y: 70, rotation: -8 }, { opacity: 1, y: 0, rotation: -1, duration: 0.5, delay: 7.14, ease: 'back.out' });
ctx.fromTo(['s3-c1-icon', 's3-c2-icon', 's3-c3-icon'], { opacity: 0, scale: 0.3 }, { opacity: 1, scale: 1, duration: 0.4, delay: 7.3, stagger: 0.08, ease: 'back.out' });
ctx.fromTo('s3-meta', { opacity: 0 }, { opacity: 1, duration: 0.4, delay: 7.5, ease: 'power2.out' });

// ===== Scene 4 入场（10.9s）— 数字 scramble 揭示 =====
ctx.fromTo('s4-kicker', { opacity: 0, y: -16 }, { opacity: 1, y: 0, duration: 0.4, delay: 10.9, ease: 'power3.out' });
ctx.fromTo('s4-num-panel', { opacity: 0, scale: 0.85, rotation: 8 }, { opacity: 1, scale: 1, rotation: -2, duration: 0.55, delay: 10.95, ease: 'back.out' });
ctx.to('s4-num', { scrambleText: { text: '3亿+', speed: 22, revealDelay: 0.05 }, duration: 1.0, delay: 11.15, ease: 'linear' });
ctx.fromTo('s4-num-label', { opacity: 0, y: 12 }, { opacity: 1, y: 0, duration: 0.4, delay: 11.5, ease: 'power2.out' });
ctx.fromTo('s4-stat1', { opacity: 0, x: 50, rotation: 12 }, { opacity: 1, x: 0, rotation: 2, duration: 0.5, delay: 11.35, ease: 'back.out' });
ctx.fromTo('s4-stat2', { opacity: 0, x: 50, rotation: -12 }, { opacity: 1, x: 0, rotation: -2, duration: 0.5, delay: 11.5, ease: 'back.out' });
ctx.fromTo('s4-tagline', { opacity: 0, y: 16 }, { opacity: 1, y: 0, duration: 0.4, delay: 11.75, ease: 'power2.out' });

// ===== Scene 5 入场（14.7s）— logo slam + CTA =====
ctx.fromTo('s5-logo', { opacity: 0, scale: 0.3, rotation: -50 }, { opacity: 1, scale: 1, rotation: -3, duration: 0.6, delay: 14.7, ease: 'back.out' });
ctx.fromTo('s5-logo-icon', { opacity: 0, scale: 0.4, rotation: -40 }, { opacity: 1, scale: 1, rotation: 0, duration: 0.5, delay: 14.95, ease: 'back.out' });
ctx.fromTo(['s5-brand-shadow', 's5-brand'], { opacity: 0, y: 30, scale: 0.92 }, { opacity: 1, y: 0, scale: 1, duration: 0.55, delay: 15.0, stagger: 0.02, ease: 'back.out' });
ctx.fromTo('s5-cta', { opacity: 0, y: 26, scale: 0.8 }, { opacity: 1, y: 0, scale: 1, duration: 0.5, delay: 15.25, ease: 'back.out' });
ctx.fromTo('s5-slogan', { opacity: 0 }, { opacity: 1, duration: 0.4, delay: 15.55, ease: 'power2.out' });
ctx.fromTo('s5-star1', { opacity: 0, scale: 0, rotation: -120 }, { opacity: 1, scale: 1, rotation: 0, duration: 0.5, delay: 15.1, ease: 'back.out' });
ctx.fromTo('s5-star2', { opacity: 0, scale: 0, rotation: 120 }, { opacity: 1, scale: 1, rotation: 0, duration: 0.5, delay: 15.2, ease: 'back.out' });

// ===== CTA 机械按压循环（push-down）=====
ctx.to('s5-cta', { y: 5, duration: 0.16, repeat: -1, yoyo: true, ease: 'linear', repeatDelay: 1.1, delay: 15.9 });

// ===== 持续呼吸 / 微运动（仅装饰，ctx.time 全局）=====
ctx.to('s1-ghost', { x: 24, duration: 6, repeat: -1, yoyo: true, ease: 'sine.inOut' });
ctx.to('s1-dot1', { scale: 1.3, duration: 1.6, repeat: -1, yoyo: true, ease: 'sine.inOut' });
ctx.to('s1-star', { rotation: 360, duration: 12, repeat: -1, ease: 'linear' });
ctx.to('s2-ghost', { x: -20, duration: 7, repeat: -1, yoyo: true, ease: 'sine.inOut' });
ctx.to('s2-star', { rotation: 360, duration: 14, repeat: -1, ease: 'linear' });
ctx.to('s3-ghost', { y: 14, duration: 8, repeat: -1, yoyo: true, ease: 'sine.inOut' });
ctx.to('s4-ghost', { x: -22, duration: 6.5, repeat: -1, yoyo: true, ease: 'sine.inOut' });
ctx.to('s4-star', { rotation: 360, duration: 12, repeat: -1, ease: 'linear' });
ctx.to('s5-ghost', { x: 20, duration: 6, repeat: -1, yoyo: true, ease: 'sine.inOut' });
ctx.to('s5-star1', { rotation: 360, duration: 11, repeat: -1, ease: 'linear' });
ctx.to('s5-star2', { rotation: -360, duration: 9, repeat: -1, ease: 'linear' });
ctx.to('s5-ray1', { opacity: 0.4, duration: 1.1, repeat: -1, yoyo: true, ease: 'sine.inOut' });
ctx.to('s5-ray3', { opacity: 0.4, duration: 1.3, repeat: -1, yoyo: true, ease: 'sine.inOut' });
